/**
 * @summary Update model configuration
 */
export const getUpdateConfigUrl = () => {
  return `/api/config`;
};

export const updateConfig = async (
  modelConfig: ModelConfig,
  options?: RequestInit,
): Promise<ModelConfig> => {
  return customFetch<ModelConfig>(getUpdateConfigUrl(), {
    ...options,
    method: "PUT",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(modelConfig),
  });
};

export const getUpdateConfigMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateConfig>>,
    TError,
    { data: BodyType<ModelConfig> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof updateConfig>>,
  TError,
  { data: BodyType<ModelConfig> },
  TContext
> => {
  const mutationKey = ["updateConfig"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateConfig>>,
    { data: BodyType<ModelConfig> }
  > = (props) => {
    const { data } = props ?? {};

    return updateConfig(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type UpdateConfigMutationResult = NonNullable<
  Awaited<ReturnType<typeof updateConfig>>
>;
export type UpdateConfigMutationBody = BodyType<ModelConfig>;
export type UpdateConfigMutationError = ErrorType<unknown>;

/**
 * @summary Update model configuration
 */
export const useUpdateConfig = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateConfig>>,
    TError,
    { data: BodyType<ModelConfig> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updateConfig>>,
  TError,
  { data: BodyType<ModelConfig> },
  TContext
> => {
  return useMutation(getUpdateConfigMutationOptions(options));
};
